/**
 * Internal method. Removes duplicate attribute by name. Settings for case sensitivity of key names.
 * @param settings case sensitivity
 * @return number of removed dupes
 */
public int removeDups(ParseSettings settings) {
    int originalSize = size;

    // Create new arrays to hold unique attributes
    String[] newKeys = new String[keys.length];
    String[] newVals = new String[vals.length];
    int newSize = 0;

    for (int i = 0; i < size; i++) {
        String currentKey = keys[i];

        // Check if this key already exists in our new array based on case sensitivity
        boolean duplicateFound = false;
        for (int j = 0; j < newSize; j++) {
            if (settings.preserveAttributeCase()) {
                // Case sensitive: keys must match exactly
                if (currentKey.equals(newKeys[j])) {
                    duplicateFound = true;
                    break;
                }
            } else {
                // Case insensitive: compare ignoring case
                if (currentKey.equalsIgnoreCase(newKeys[j])) {
                    duplicateFound = true;
                    break;
                }
            }
        }

        // Only add if not a duplicate
        if (!duplicateFound) {
            newKeys[newSize] = currentKey;
            newVals[newSize] = vals[i];
            newSize++;
        }
    }

    // Update this instance with the deduplicated arrays
    keys = newKeys;
    vals = newVals;
    size = newSize;

    return originalSize - newSize; // Return number of removed duplicates
}

